95	Create `components/ChatPane.tsx` with this content:
96	
97	```tsx
98	"use client";
99	
100	import { FormEvent, useState } from "react";
101	import type { ChatMessage } from "@/lib/shared/schemas";
102	
103	type LocalMessage = Pick<ChatMessage, "id" | "role" | "content">;
104	
105	export function ChatPane({ messages, onTurnComplete }: { messages: ChatMessage[]; onTurnComplete: () => Promise<void> }) {
106	  const [draft, setDraft] = useState("");
107	  const [localMessages, setLocalMessages] = useState<LocalMessage[]>([]);
108	  const [isSending, setIsSending] = useState(false);
109	  const [error, setError] = useState<string | null>(null);
110	
111	  const visibleMessages = [...messages, ...localMessages];
112	
113	  async function submit(event: FormEvent<HTMLFormElement>) {
114	    event.preventDefault();
115	    const message = draft.trim();
116	    if (!message || isSending) return;
117	
118	    setDraft("");
119	    setError(null);
120	    setIsSending(true);
121	
122	    const userMessage: LocalMessage = { id: crypto.randomUUID(), role: "user", content: message };
123	    const assistantMessage: LocalMessage = { id: crypto.randomUUID(), role: "assistant", content: "" };
124	    setLocalMessages((current) => [...current, userMessage, assistantMessage]);
125	
126	    try {
127	      const response = await fetch("/api/chat", {
128	        method: "POST",
129	        headers: { "content-type": "application/json" },
130	        body: JSON.stringify({ message }),
131	      });
132	
133	      if (!response.ok || !response.body) {
134	        const payload = await response.json().catch(() => ({ error: "Chat request failed" }));
135	        throw new Error(payload.error ?? "Chat request failed");
136	      }
137	
138	      const reader = response.body.getReader();
139	      const decoder = new TextDecoder();
140	
141	      while (true) {
142	        const { done, value } = await reader.read();
143	        if (done) break;
144	        const chunk = decoder.decode(value, { stream: true });
145	        setLocalMessages((current) => current.map((item) => item.id === assistantMessage.id ? { ...item, content: item.content + chunk } : item));
146	      }
147	
148	      await onTurnComplete();
149	      setLocalMessages([]);
150	    } catch (caught) {
151	      setError(caught instanceof Error ? caught.message : "Chat failed");
152	    } finally {
153	      setIsSending(false);
154	    }
155	  }
156	
157	  return (
158	    <section className="chat-pane">
159	      <div className="chat-header">
160	        <p className="eyebrow">Profile Builder</p>
161	        <h1>Tell Atlas how you like to travel</h1>
162	        <p>Chat naturally. The profile panel updates with durable preferences and flags contradictions.</p>
163	      </div>
164	
165	      <div className="messages">
166	        {visibleMessages.length === 0 && (
167	          <div className="empty-state">Try: "I live in Denver, like food trips, and I am considering Tokyo in the fall."</div>
168	        )}
169	        {visibleMessages.map((message) => (
170	          <article className={`message ${message.role}`} key={message.id}>
171	            <strong>{message.role === "user" ? "You" : "Atlas"}</strong>
172	            <p>{message.content || "..."}</p>
173	          </article>
174	        ))}
175	      </div>
176	
177	      {error && <p className="error-banner">{error}</p>}
178	
179	      <form className="composer" onSubmit={submit}>
180	        <textarea value={draft} onChange={(event) => setDraft(event.target.value)} placeholder="Share a travel preference or ask about a destination..." />
181	        <button disabled={isSending}>{isSending ? "Sending" : "Send"}</button>
182	      </form>
183	    </section>
184	  );
185	}
