198	import type { AppState, ProviderStatus } from "@/lib/shared/schemas";
199	
200	type StateResponse = AppState & { provider: ProviderStatus };
201	
202	const emptyState: StateResponse = {
203	  profile: {},
204	  messages: [],
205	  conflicts: [],
206	  provider: { configured: false, model: "", baseUrl: "", missing: ["OPENROUTER_API_KEY"] },
207	};
208	
209	export default function Home() {
210	  const [state, setState] = useState<StateResponse>(emptyState);
211	  const [isLoading, setIsLoading] = useState(true);
212	
213	  async function refreshState() {
214	    const response = await fetch("/api/state", { cache: "no-store" });
215	    if (!response.ok) throw new Error("Failed to load profile state");
216	    setState(await response.json());
217	  }
218	
219	  async function reset() {
220	    await fetch("/api/reset", { method: "POST" });
221	    await refreshState();
222	  }
223	
224	  useEffect(() => {
225	    refreshState().finally(() => setIsLoading(false));
226	  }, []);
227	
228	  if (isLoading) {
229	    return <main className="app-shell"><p>Loading profile...</p></main>;
230	  }
231	
232	  return (
233	    <main className="app-shell">
234	      <ChatPane messages={state.messages} onTurnComplete={refreshState} />
235	      <ProfilePanel state={state} provider={state.provider} onReset={reset} />
236	    </main>
237	  );
238	}
