import type { DestinationInfo } from "@/lib/shared/schemas";

const DESTINATIONS: DestinationInfo[] = [
  {
    name: "Tokyo",
    bestSeasons: ["spring", "fall"],
    knownFor: ["food", "design", "transit", "neighborhood wandering"],
